queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?gate_agents a :GateAgents .
    ?gate_agents p:name ?name .
    ?gate_agents p:Language ?language_f .
    FILTER(STR(?language_f) = "Spanish")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?pilots a :Pilots .
    ?pilots p:name ?name .
    ?pilots p:Language ?language_f .
    FILTER(STR(?language_f) = "Spanish")
    BIND(?name AS ?o0)
  }
}

